import sse_sampler

QASM = """OPENQASM 3.0;
include \"stdgates.inc\";
qubit[2] q;
bit[2] c;
x q[0];
cx q[0], q[1];
c = measure q;
"""

for i in range(3):
    shots = 100 + i * 10
    print(f"## iteration {i}: shots={shots} ##")
    job = sse_sampler.req_transpile_and_exec([QASM], shots, {"transpiler_lib": None})
    print(job.status)

print("## finish ##")
